<?php
$pageTitle='Decision Support';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('decision_support');
$pdo=getDB();$user=currentUser();
if($_SERVER['REQUEST_METHOD']==='POST'){try{$action=(string)($_POST['action']??'');if($action==='case'){$number=nextScopedDocumentNumber($pdo,'decision_support_case','DSC',operationalScope($pdo));$pdo->prepare('INSERT INTO '.table('decision_support_cases').' (case_number,case_title,module,decision_question,status,created_by) VALUES (?,?,?,?, "draft", ?)')->execute([$number,trim((string)$_POST['case_title']),trim((string)$_POST['module']),trim((string)$_POST['decision_question']),(int)($user['id']??0)?:null]);flash('success','Decision case created.');}elseif($action==='option'){$score=max(0,(float)$_POST['estimated_benefit'])-max(0,(float)$_POST['estimated_cost'])-max(0,(float)$_POST['risk_score']);$pdo->prepare('INSERT INTO '.table('decision_support_options').' (decision_support_case_id,option_title,pros,cons,estimated_cost,estimated_benefit,risk_score,recommendation_score) VALUES (?,?,?,?,?,?,?,?)')->execute([(int)$_POST['case_id'],trim((string)$_POST['option_title']),trim((string)$_POST['pros']),trim((string)$_POST['cons']),max(0,(float)$_POST['estimated_cost']),max(0,(float)$_POST['estimated_benefit']),max(0,(float)$_POST['risk_score']),$score]);flash('success','Decision option added.');}elseif($action==='select'){$pdo->prepare('UPDATE '.table('decision_support_cases').' SET selected_option_id=?,status="selected",closed_at=NOW() WHERE id=?')->execute([(int)$_POST['option_id'],(int)$_POST['case_id']]);flash('success','Decision option selected.');}}catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'decision-support']);flash('error',$e->getMessage());}redirect(ADMIN_URL.'/erp/decision-support.php');}
$cases=$pdo->query('SELECT * FROM '.table('decision_support_cases').' ORDER BY created_at DESC LIMIT 100')->fetchAll();$options=$pdo->query('SELECT o.*,c.case_number FROM '.table('decision_support_options').' o LEFT JOIN '.table('decision_support_cases').' c ON c.id=o.decision_support_case_id ORDER BY o.recommendation_score DESC,o.created_at DESC LIMIT 200')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Management Decisions</div><h2 class="h4 mb-1">Decision Support</h2><p class="text-secondary mb-0">Create decision cases, score options, compare cost/benefit/risk, and record selected decisions.</p></div></div><div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="case"><h2 class="h5 mb-3">Create Decision Case</h2><input class="form-control mb-2" name="case_title" placeholder="Decision title"><input class="form-control mb-2" name="module" placeholder="Sales / Finance / Operations"><textarea class="form-control mb-3" name="decision_question" rows="3" placeholder="What decision do we need to make?"></textarea><button class="btn btn-brand w-100">Create Case</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="option"><h2 class="h5 mb-3">Add Option</h2><select class="form-select mb-2" name="case_id"><?php foreach($cases as $c): ?><option value="<?php echo (int)$c['id']; ?>"><?php echo esc($c['case_number'].' · '.$c['case_title']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="option_title" placeholder="Option title"><textarea class="form-control mb-2" name="pros" rows="2" placeholder="Pros"></textarea><textarea class="form-control mb-2" name="cons" rows="2" placeholder="Cons"></textarea><input class="form-control mb-2" type="number" step="0.01" name="estimated_cost" placeholder="Estimated cost"><input class="form-control mb-2" type="number" step="0.01" name="estimated_benefit" placeholder="Estimated benefit"><input class="form-control mb-3" type="number" step="0.01" name="risk_score" placeholder="Risk score"><button class="btn btn-outline-primary w-100">Add Option</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Decision Cases</h2><table class="table"><thead><tr><th>Case</th><th>Module</th><th>Question</th><th>Status</th></tr></thead><tbody><?php foreach($cases as $c): ?><tr><td><strong><?php echo esc($c['case_number']); ?></strong><div class="small text-secondary"><?php echo esc($c['case_title']); ?></div></td><td><?php echo esc($c['module']); ?></td><td><?php echo esc($c['decision_question']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($c['status'])); ?>"><?php echo esc($c['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Scored Options</h2><table class="table align-middle"><thead><tr><th>Option</th><th>Cost</th><th>Benefit</th><th>Risk</th><th>Score</th><th></th></tr></thead><tbody><?php foreach($options as $o): ?><tr><td><strong><?php echo esc($o['option_title']); ?></strong><div class="small text-secondary"><?php echo esc($o['case_number']); ?></div></td><td><?php echo money($o['estimated_cost']); ?></td><td><?php echo money($o['estimated_benefit']); ?></td><td><?php echo number_format((float)$o['risk_score'],1); ?></td><td><?php echo number_format((float)$o['recommendation_score'],1); ?></td><td><form method="post"><input type="hidden" name="action" value="select"><input type="hidden" name="case_id" value="<?php echo (int)$o['decision_support_case_id']; ?>"><input type="hidden" name="option_id" value="<?php echo (int)$o['id']; ?>"><button class="btn btn-sm btn-success">Select</button></form></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>